mapper.insert:
INSERT INTO SHOP_MEMBER (
  MEM_ID
  , MEM_PW
  , MEM_NAME
  , MEM_TEL
  , MEM_EMAIL
  , MEM_ADDR
  , ADDR_DETAIL
  , PW_KEY
  , PW_ANSWER
) VALUES (
  #{memId}
  , #{memPw}
  , #{memName}
  , CONCAT(#{memTelArr[0]}, '-', #{memTelArr[1]}, '-', #{memTelArr[2]})
  , #{memEmail}
  , #{memAddr}
  , #{addrDetail}
  , #{pwKey}
  , #{pwAnswer}
)

mapper.select:
